// Parse the Perplexity response into structured newsletter JSON
const response = $('write_newsletter').first().json;
const text = response.message || response.content || '';
const writeCitations = response.citations || [];

let newsletter;
try {
  // Try direct JSON parse
  newsletter = JSON.parse(text);
} catch (e) {
  try {
    // Try extracting from markdown code block
    const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (jsonMatch) {
      newsletter = JSON.parse(jsonMatch[1].trim());
    } else {
      // Try finding JSON object in text
      const objMatch = text.match(/\{[\s\S]*\}/);
      if (objMatch) {
        newsletter = JSON.parse(objMatch[0]);
      } else {
        // Fallback: wrap raw text as single-section newsletter
        newsletter = {
          subject_line: $('workflow_trigger').first().json.topic || 'Newsletter',
          pre_header: 'Your latest newsletter',
          intro: '',
          sections: [{ headline: 'Newsletter', body: text }],
          outro: ''
        };
      }
    }
  } catch (e2) {
    // Last resort fallback
    newsletter = {
      subject_line: $('workflow_trigger').first().json.topic || 'Newsletter',
      pre_header: 'Your latest newsletter',
      intro: '',
      sections: [{ headline: 'Newsletter', body: text }],
      outro: ''
    };
  }
}

return [{ json: { output: newsletter, citations: writeCitations } }];

// Safety net: inject source links into sections that don't already have them
const researchData = $('research_topic').first().json;
const researchCitations = researchData.citations || [];
const writeCitations = $json.citations || [];
const researchText = researchData.message || '';

// Parse SOURCE blocks from research text
const sources = [];
const sourceBlocks = researchText.split('---').filter(b => b.includes('SOURCE'));
for (const block of sourceBlocks) {
  const titleMatch = block.match(/Title:\s*(.+)/i);
  const urlMatch = block.match(/URL:\s*(https?:\/\/[^\s]+)/i);
  if (titleMatch && urlMatch) {
    sources.push({ title: titleMatch[1].trim(), url: urlMatch[1].trim() });
  }
}

// Fallback: use raw citations arrays
if (sources.length === 0) {
  const allCitations = [...new Set([...researchCitations, ...writeCitations])];
  for (const url of allCitations) {
    const domain = url.replace(/https?:\/\/(www\.)?/, '').split('/')[0];
    sources.push({ title: domain, url });
  }
}

const output = $json.output || {};
const sections = output.sections || [];

// Only add links to sections that don't already have markdown links
const enrichedSections = sections.map((section, i) => {
  if (section.body && /\[.+?\]\(https?:\/\/.+?\)/.test(section.body)) {
    return section; // Already has links
  }
  const startIdx = (i * 2) % Math.max(sources.length, 1);
  const sectionSources = sources.slice(startIdx, startIdx + 2);
  if (sectionSources.length === 0) return section;

  const links = sectionSources
    .map(s => '[' + s.title + '](' + s.url + ')')
    .join(' | ');

  return {
    ...section,
    body: section.body + '\n\n**Read more:** ' + links
  };
});

return [{
  json: {
    output: {
      ...output,
      sections: enrichedSections
    }
  }
}];

